args.query:
SELECT COUNT(*) AS n_total,
       SUM(CASE WHEN "Patient_description" ILIKE '%vital status:% Alive%' OR "Patient_description" ILIKE '%vital status: Alive%' OR "Patient_description" ILIKE '%vital status recorded as Alive%' OR "Patient_description" ILIKE '%Current vital status: Alive%' THEN 1 ELSE 0 END) AS n_alive
FROM clinical_info;

